// L1-A Preprocessor v3 — fixed path + all routing aliases
const triggerData = $('Telegram Trigger').first().json;
const msg = triggerData.body?.message || triggerData.message || {};
const text = msg.text || msg.caption || '';
const userId = msg.from?.id || 0;
const chatId = msg.chat?.id || userId;

function simpleHash(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16);
}

const content_clean = text.trim().replace(/\s+/g, ' ');
const thaiRegex = /[฀-๿]/;
const lang_detected = thaiRegex.test(content_clean) ? 'th' : 'en';
const msg_hash = simpleHash(`${userId}:${content_clean}`);

let msg_type = 'chat';
if (text.startsWith('/start')) msg_type = 'start';
else if (text.startsWith('/rate')) msg_type = 'feedback';
else if (text.toUpperCase() === 'APPROVE' || text.toUpperCase() === 'REJECT') msg_type = 'approval';

return [{ json: {
  content_raw: text,
  content_clean,
  text: content_clean,
  lang_detected,
  isThai: lang_detected === 'th',
  msg_hash,
  hash: msg_hash,
  msg_type,
  isStart: msg_type === 'start',
  isApproval: msg_type === 'approval',
  isChat: msg_type === 'chat',
  user_id: userId, userId,
  chat_id: chatId, chatId,
  firstName: msg.from?.first_name || '',
  username: msg.from?.username || '',
  preprocessed_at: new Date().toISOString()
} }];

