=🔔 New Registration

Name: {{ $('L1-A Preprocessor').first().json.firstName }}
Username: @{{ $('L1-A Preprocessor').first().json.username }}
Chat ID: {{ $('L1-A Preprocessor').first().json.chatId }}

Reply:
APPROVE {{ $('L1-A Preprocessor').first().json.chatId }}
or REJECT {{ $('L1-A Preprocessor').first().json.chatId }}

parameters.jsCode:
const text = $('L1-A Preprocessor').first().json.text.toUpperCase();
const parts = text.split(' ');
const action = parts[0];
const targetId = parseInt(parts[1]);
const newStatus = action === 'APPROVE' ? 'approved' : 'rejected';
return [{ json: { action, targetId, newStatus } }];

const data = $input.first().json;
// Handle OpenAI format (choices[0].message.content) or Dify format (data.answer)
let reply = (data.choices && data.choices[0] && data.choices[0].message && data.choices[0].message.content)
  || data.answer || data.text
  || 'ขออภัย ไม่สามารถตอบได้ตอนนี้ครับ';
if (reply.length > 4096) reply = reply.substring(0, 4090) + '...[ต่อ]';
const agent = data.model ? 'litellm' : (data.metadata?.usage ? 'dify' : 'unknown');
return [{ json: { reply, reply_text: reply, agent } }];

